URL de imagen: {{ $json.image_url }}
Modo: {{ $json.modo }}
Paso: {{ $json.paso }}
Datos del paciente: {{ JSON.stringify($json.datos_paciente) }}
Session ID: {{ $json.session_id }}
Conversation ID: {{ $json.conversation_id }}
Account ID: {{ $json.account_id }}
Platform: {{ $json.platform }}
Timestamp actividad: {{ $json.timestamp_actividad }}
Fecha/hora actual (debes usarla en timestamp_actividad): {{ $now }}

---

INSTRUCCIÓN FINAL:
- Sigue ESTRICTAMENTE el prompt del sistema (BOT UNISA).
- En el paso ESPERANDO_FOTO_CEDULA: PRIMERO verifica image_url. Si hay imagen (no vacía y empieza con http), IGNORA el texto y procesa la imagen.
- Tu respuesta debe ser ÚNICAMENTE un objeto JSON válido, sin texto adicional, sin markdown, sin comillas escapadas.
- Los campos session_id, conversation_id, account_id, platform deben copiarse de los valores proporcionados arriba.
- timestamp_actividad debe ser el valor de "Fecha/hora actual" que se te pasó.{{ $json.text }}

parameters.jsCode:
// Versión completa que mantiene todos los campos
const outputItem = items[0].json;
const conversationItem = items[1].json;

// Combinar preservando todo
const fullData = {
  // Campos de la conversación
  text: conversationItem.text,
  session_id: conversationItem.session_id,
  image_url: conversationItem.image_url,
  platform: conversationItem.platform,
  account_id: conversationItem.account_id,
  conversation_id: conversationItem.conversation_id,
  estado_actual: conversationItem.estado_actual,
  datos_paciente: conversationItem.datos_paciente,

  // Campos del output
  output: outputItem.output,  // Mantenemos el output original

  // Campos para Chatwoot
  content: outputItem.output,  // Para el API de Chatwoot
  message_type: "outgoing",
  private: false
};

return [{
  json: fullData
}];

// Obtener todos los datos de entrada
const allItems = $input.all();

// Si hay múltiples items, asumimos que el primero tiene output y el segundo los datos de sesión
let outputData = "";
let sessionData = {};

if (allItems.length >= 2) {
  // Caso 1: Dos items separados (uno con output, otro con datos de sesión)
  outputData = allItems[0].json.output || allItems[0].json.text || "";
  sessionData = allItems[1].json;
} else if (allItems.length === 1) {
  // Caso 2: Un solo item que contiene el array
  const entrada = allItems[0].json;

  if (Array.isArray(entrada)) {
    // Es un array como en tu ejemplo
    if (entrada.length >= 2) {
      outputData = entrada[0].output || entrada[0].text || "";
      sessionData = entrada[1];
    } else if (entrada.length === 1) {
      outputData = entrada[0].output || entrada[0].text || "";
      sessionData = entrada[0]; // Usar el mismo objeto para ambos
    }
  } else {
    // Es un objeto único
    outputData = entrada.output || entrada.text || "";
    sessionData = entrada;
  }
}

// Parsear el string output para extraer el valor de equipo_asignado
let equipoAsignado = "Agendamiento_Directo"; // valor por defecto

if (outputData) {
  // Buscar el valor entre comillas después de "equipo_asignado:"
  const match = outputData.match(/equipo_asignado:\s*"([^"]+)"/);
  if (match && match[1]) {
    equipoAsignado = match[1];
  }
}

// Crear el objeto datos_paciente
const datosPaciente = sessionData.estado_actual?.datos_paciente || sessionData.datos_paciente || {};

// Agregar el equipo_asignado al objeto datos_paciente
datosPaciente.equipo_asignado = equipoAsignado;

// También puedes agregar otros campos si es necesario
datosPaciente.requiere_seguimiento = true;

// Crear el objeto de salida
const salida = {
  session_id: sessionData.session_id || "",
  estado: {
    modo: "AGENDANDO_CITA",
    paso: "SOLICITAR_TELEFONO",
    datos_paciente: datosPaciente,
    timestamp: sessionData.estado_actual?.timestamp || new Date().toISOString()
  }
};

// Devolver la salida
return salida;

return items.map(item => {
  try {
    const parsed = JSON.parse(item.json.output);
    return { json: parsed };
  } catch (e) {
    return {
      json: {
        success: false,
        error: 'JSON inválido recibido del LLM',
        raw_output: item.json.output
      }
    };
  }
});

// Extraer estado actual
const estado = $json.estado_actual || {};
const datos = estado.datos_paciente || {};

// Construir objeto de salida con nombres originales (SIN prefijo)
const output = {
  // Mensaje e imagen
  text: $json.text || '',
  image_url: $json.image_url || '',

  // Metadatos de sesión
  session_id: $json.session_id || '',
  conversation_id: $json.conversation_id || '',
  account_id: $json.account_id || '',
  platform: $json.platform || '',

  // Estado actual desglosado (plano)
  modo: estado.modo || null,
  paso: estado.paso || null,
  datos_paciente: datos,
  timestamp_actividad: estado.timestamp_actividad || new Date().toISOString(),

  // Opcional: conservar el estado_actual original por si otros nodos lo necesitan
  estado_actual: estado
};

return [{ json: output }];
